import React, {
  useState,
} from "react";
import axios from "axios";

const CreateEmergencyRequest = () => {
  const [formData, setFormData] =
    useState({
      requestedBy: "",
      location: "",
    });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]:
        e.target.value,
    });
  };

  const handleSubmit =
    async (e) => {
      e.preventDefault();

      try {
        const res =
          await axios.post(
            "http://localhost:3000/api/emergency/create",
            formData
          );

        alert(
          res.data.message
        );

        setFormData({
          requestedBy: "",
          location: "",
        });
      } catch (err) {
        console.log(err);
      }
    };

  return (
    <div className="container mt-4">

      <div className="card p-4">

        <h3>
          Emergency Request
        </h3>

        <form
          onSubmit={
            handleSubmit
          }
        >
          <input
            type="text"
            name="requestedBy"
            placeholder="User Id"
            className="form-control mb-3"
            value={
              formData.requestedBy
            }
            onChange={
              handleChange
            }
          />

          <input
            type="text"
            name="location"
            placeholder="Location Id"
            className="form-control mb-3"
            value={
              formData.location
            }
            onChange={
              handleChange
            }
          />

          <button
            className="btn btn-danger"
          >
            Create Request
          </button>

        </form>

      </div>

    </div>
  );
};

export default CreateEmergencyRequest;
